@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="notepad-container">
    <textarea class="notepad-textarea" @bind="Content" @bind:event="oninput" placeholder="Type your notes here..." />

    <div class="notepad-toolbar">
        <div class="notepad-status">
            @if (_lastSavedAt is not null)
            {
                <span>Last saved at @_lastSavedAt.Value.ToString("HH:mm:ss")</span>
            }
            else
            {
                <span>Not saved yet</span>
            }
        </div>
        <div class="notepad-actions">
            <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
            <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
        </div>
    </div>
</div>

@code {
    private NotepadInterop? _interop;
    private Timer? _autoSaveTimer;
    private string _content = string.Empty;
    private string _lastSavedContent = string.Empty;
    private DateTime? _lastSavedAt;

    private string Content
    {
        get => _content;
        set
        {
            _content = value;
            _ = UpdateLeaveGuardAsync();
        }
    }

    private bool HasUnsavedChanges => _content != _lastSavedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            var saved = await _interop.LoadContentAsync();
            if (!string.IsNullOrEmpty(saved))
            {
                _content = saved;
                _lastSavedContent = saved;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(OnAutoSave, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async void OnAutoSave(object? state)
    {
        await InvokeAsync(async () =>
        {
            if (HasUnsavedChanges)
            {
                await SaveAsync();
                StateHasChanged();
            }
        });
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_interop is null) return;

        await _interop.SaveContentAsync(_content);
        _lastSavedContent = _content;
        _lastSavedAt = DateTime.Now;
        await _interop.DisableLeaveGuardAsync();
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        _content = string.Empty;
        _lastSavedContent = string.Empty;
        _lastSavedAt = null;
        await _interop.ClearContentAsync();
        await _interop.DisableLeaveGuardAsync();
    }

    private async Task UpdateLeaveGuardAsync()
    {
        if (_interop is null) return;

        if (HasUnsavedChanges)
            await _interop.EnableLeaveGuardAsync();
        else
            await _interop.DisableLeaveGuardAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
            await _autoSaveTimer.DisposeAsync();

        if (_interop is not null)
            await _interop.DisposeAsync();
    }
}

