.notepad-container {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    max-width: 48rem;
}

.notepad-textarea {
    width: 100%;
    min-height: 20rem;
    padding: 0.75rem;
    font-family: inherit;
    font-size: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    resize: vertical;
}

.notepad-textarea:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 0.25rem rgba(13, 110, 253, 0.25);
}

.notepad-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.notepad-status {
    color: #6c757d;
    font-size: 0.875rem;
}

.notepad-actions {
    display: flex;
    gap: 0.5rem;
}

